// Striped Lighthouse — a tapered tower with alternating red/white horizontal
// bands, a flared gallery + railing ring near the top, a domed lantern room
// enclosing a glowing light, all standing on a wider base.
//
// Parametric (api.params) + colorable (api.label). The alternating stripes use
// a two-label trick: even bands -> "bandsRed", odd bands -> "bandsWhite", so
// two paint colors cover the whole tower no matter how many bands there are.
const { Manifold, CrossSection } = api;

const p = api.params({
  bands:       { type: 'int',     default: 7,   min: 3,   max: 15,  step: 1,   label: 'Stripe bands' },
  taper:       { type: 'number',  default: 0.45, min: 0.0, max: 0.8, step: 0.05, label: 'Tower taper', help: 'Top radius as a fraction narrower than the base.' },
  towerHeight: { type: 'number',  default: 80,  min: 40,  max: 140, step: 1,   unit: 'mm', label: 'Tower height' },
  baseRadius:  { type: 'number',  default: 22,  min: 14,  max: 36,  step: 1,   unit: 'mm', label: 'Base radius' },
  galleryFlare:{ type: 'number',  default: 6,   min: 0,   max: 12,  step: 0.5, unit: 'mm', label: 'Gallery overhang' },
  railing:     { type: 'boolean', default: true, label: 'Railing posts' },
  lanternGlass:{ type: 'select',  default: 'panes', options: ['panes', 'open', 'solid'], label: 'Lantern style' },
});

// ---------------------------------------------------------------------------
// Radii. The tower tapers linearly from baseR (at the gallery floor) up to
// topR. The base plinth is a touch wider than the tower's bottom.
// ---------------------------------------------------------------------------
const baseR  = p.baseRadius;
const topR   = baseR * (1 - p.taper);            // narrower top
const towerR = (t) => baseR + (topR - baseR) * t; // t in [0,1] over tower height

// A radial profile -> revolved solid frustum between two heights.
// X = radial distance, Y = height (after revolve, Y becomes world Z).
function frustum(z0, z1, r0, r1) {
  const cs = CrossSection.ofPolygons([[
    [0, z0],
    [r0, z0],
    [r1, z1],
    [0, z1],
  ]]);
  return Manifold.revolve(cs);
}

const parts = [];

// ---------------------------------------------------------------------------
// 1. BASE — a wider, slightly tapered plinth the tower stands on.
// ---------------------------------------------------------------------------
const baseH = baseR * 0.55;
const plinthR = baseR + 4;
const base = api.label(
  frustum(0, baseH, plinthR, baseR + 1.5).add(
    // a thin foot lip at the very bottom for a finished look
    frustum(0, baseH * 0.28, plinthR + 2.5, plinthR + 1.0)
  ),
  'base'
);
parts.push(base);

// ---------------------------------------------------------------------------
// 2. STRIPED TOWER — N stacked frustum bands. Even -> red, odd -> white.
//    Each band overlaps its neighbour by `overlap` units so the booleans fuse
//    into one solid (the labels still trace per-band through the union).
// ---------------------------------------------------------------------------
const towerZ0 = baseH;                  // tower starts on top of the base
const bandH = p.towerHeight / p.bands;
const overlap = Math.min(0.75, bandH * 0.25); // >= 0.5 where bandH allows

for (let i = 0; i < p.bands; i++) {
  const t0 = i / p.bands;
  const t1 = (i + 1) / p.bands;
  const z0 = towerZ0 + i * bandH - (i > 0 ? overlap : 0);
  const z1 = towerZ0 + (i + 1) * bandH;
  const band = frustum(z0, z1, towerR(t0), towerR(t1));
  parts.push(api.label(band, i % 2 === 0 ? 'bandsRed' : 'bandsWhite'));
}

const galleryZ = towerZ0 + p.towerHeight; // top of the tower / gallery floor

// ---------------------------------------------------------------------------
// 3. GALLERY — a flared deck ring near the top, with optional railing posts.
// ---------------------------------------------------------------------------
const galleryR = topR + p.galleryFlare;
const deckH = 3.0;
// Flared deck: underside slopes out from the tower, top is a flat ring.
let gallery = frustum(galleryZ - 1.0, galleryZ + deckH * 0.5, topR, galleryR)
  .add(frustum(galleryZ + deckH * 0.5, galleryZ + deckH, galleryR, galleryR));

if (p.railing) {
  // A thin rail ring on posts around the deck edge.
  const postH = deckH + 5;
  const postR = 0.9;
  const post = Manifold.cylinder(postH, postR, postR)
    .translate([galleryR - 1.6, 0, galleryZ + deckH * 0.5]);
  const posts = api.circularPattern(post, 10, { axis: 'z' });
  const railRing = frustum(
    galleryZ + deckH + 4.0, galleryZ + deckH + 5.0,
    galleryR - 0.6, galleryR - 0.6
  ).subtract(
    frustum(galleryZ + deckH + 3.5, galleryZ + deckH + 5.5,
      galleryR - 1.8, galleryR - 1.8)
  );
  gallery = gallery.add(posts).add(railRing);
}
parts.push(api.label(gallery, 'gallery'));

// ---------------------------------------------------------------------------
// 4. LANTERN ROOM + LIGHT — a glass-walled drum on the gallery floor, with a
//    glowing light core inside. Then a green dome cap on top.
// ---------------------------------------------------------------------------
const lanternZ0 = galleryZ + deckH;
const lanternR = topR + 0.5;
const lanternH = baseR * 1.0;

// The light core: a bright cylinder + sphere "bulb" inside the lantern. A short
// pedestal reaches down through the gallery deck so the core fuses to the
// structure (otherwise the bulb floats as its own component).
const lightZ = lanternZ0 + lanternH * 0.45;
const pedestal = Manifold.cylinder(lanternH * 0.25 + 1.5, lanternR * 0.5, lanternR * 0.5)
  .translate([0, 0, galleryZ + deckH - 1.0]); // dip 1mm into the deck below
const lightCore = api.label(
  pedestal
    .add(Manifold.cylinder(lanternH * 0.55, lanternR * 0.55, lanternR * 0.5)
      .translate([0, 0, lanternZ0 + lanternH * 0.12]))
    .add(Manifold.sphere(lanternR * 0.6).translate([0, 0, lightZ])),
  'light'
);
parts.push(lightCore);

// Lantern frame: top & bottom rings always, plus four corner posts that bridge
// the two rings in EVERY style (so the upper assembly never floats off no
// matter the glazing). 'panes' adds slim mullions, 'solid' adds a glass drum,
// 'open' keeps just the four structural posts.
const ringBot = frustum(lanternZ0, lanternZ0 + 2.0, lanternR + 1.0, lanternR + 1.0)
  .subtract(frustum(lanternZ0 - 0.5, lanternZ0 + 2.5, lanternR - 0.6, lanternR - 0.6));
const ringTop = frustum(lanternZ0 + lanternH - 2.0, lanternZ0 + lanternH, lanternR + 1.0, lanternR + 1.0)
  .subtract(frustum(lanternZ0 + lanternH - 2.5, lanternZ0 + lanternH + 0.5, lanternR - 0.6, lanternR - 0.6));

// Four corner posts spanning the full lantern height (overlap both rings).
const corner = Manifold.cube([1.6, 1.6, lanternH + 1.0], true)
  .translate([lanternR + 0.2, 0, lanternZ0 + lanternH * 0.5]);
const corners = api.circularPattern(corner, 4, { axis: 'z' });

let lantern = ringBot.add(ringTop).add(corners);

if (p.lanternGlass === 'panes') {
  const mull = Manifold.cube([1.4, 2.2, lanternH], true)
    .translate([lanternR + 0.2, 0, lanternZ0 + lanternH * 0.5]);
  lantern = lantern.add(api.circularPattern(mull, 8, { axis: 'z' }));
} else if (p.lanternGlass === 'solid') {
  // A glazing drum enclosing the light. Punch small vent slots through the wall
  // so the interior air pocket connects to the outside — otherwise the sealed
  // drum traps a cavity that reads as a second surface shell.
  let drum = frustum(lanternZ0 + 1.0, lanternZ0 + lanternH - 1.0, lanternR + 0.9, lanternR + 0.9)
    .subtract(frustum(lanternZ0 + 0.5, lanternZ0 + lanternH - 0.5, lanternR - 1.1, lanternR - 1.1));
  const vent = Manifold.cube([6, 3, 2.5], true)
    .translate([lanternR, 0, lanternZ0 + lanternH - 2.0]); // through the wall, near top
  drum = drum.subtract(api.circularPattern(vent, 6, { axis: 'z' }));
  lantern = lantern.add(drum);
}
parts.push(api.label(lantern, 'gallery'));

// ---------------------------------------------------------------------------
// 5. DOME — a revolved hemispherical cap with a little finial on top.
// ---------------------------------------------------------------------------
const domeZ0 = lanternZ0 + lanternH - 0.5; // overlap into the lantern top ring
const domeR = lanternR + 1.0;
const domeH = domeR * 0.95;
const domeProfile = [];
const DSEG = 16;
domeProfile.push([0, domeZ0]);
domeProfile.push([domeR, domeZ0]);
for (let i = 0; i <= DSEG; i++) {
  const a = (i / DSEG) * (Math.PI / 2);
  domeProfile.push([Math.cos(a) * domeR, domeZ0 + Math.sin(a) * domeH]);
}
let dome = Manifold.revolve(CrossSection.ofPolygons([domeProfile]));
// finial spike
dome = dome.add(
  Manifold.cylinder(domeH * 0.5, 1.2, 0.0)
    .translate([0, 0, domeZ0 + domeH - 0.3])
);
parts.push(api.label(dome, 'dome'));

// ---------------------------------------------------------------------------
// Assemble. Everything overlaps its neighbour, so it fuses to one component.
// ---------------------------------------------------------------------------
return api.expectUnion(parts, { expectComponents: 1 });

